const { expect } = chai;
const BASE = (process.env.OM_BASE_URL || 'http://localhost:8888').replace(/\/$/, '') + '/api/v3/openmeter';
const KEY = process.env.OM_API_KEY || '';
const HDRS = { 'Content-Type': 'application/json', ...(KEY ? { 'Authorization': `Bearer ${KEY}` } : {}) };
const sfx = `${Date.now()}_${Math.floor(Math.random() * 9999)}`;

async function api(method, path, body) {
  const resp = await fetch(`${BASE}${path}`, {
    method,
    headers: HDRS,
    ...(body !== undefined ? { body: JSON.stringify(body) } : {})
  });
  let json = null;
  try { json = await resp.json(); } catch (_) {}
  return { status: resp.status, json };
}

const meterKey = `test_meter_${sfx}`;

// 1. Create meter with sum aggregation, value_property, and a dimension.
let r = await api('POST', '/meters', {
  key: meterKey,
  name: `Test Meter ${sfx}`,
  aggregation: 'sum',
  event_type: 'api_call',
  value_property: '$.tokens',
  dimensions: { model: '$.model' }
});
expect(r.status, '1. Create → 201').to.equal(201);
expect(r.json.key, '1. key').to.equal(meterKey);
expect(r.json.aggregation, '1. aggregation').to.equal('sum');
expect(r.json.value_property, '1. value_property').to.equal('$.tokens');
expect(r.json.dimensions && r.json.dimensions.model, '1. dimension model').to.equal('$.model');
const meterId = r.json.id;
expect(meterId, '1. id present').to.be.ok;

// 2. Get by ID.
r = await api('GET', `/meters/${meterId}`);
expect(r.status, '2. Get → 200').to.equal(200);
expect(r.json.id, '2. id').to.equal(meterId);
expect(r.json.name, '2. name').to.equal(`Test Meter ${sfx}`);
expect(r.json.event_type, '2. event_type').to.equal('api_call');

// 3. List and verify appears.
r = await api('GET', '/meters?page[size]=100');
expect(r.status, '3. List → 200').to.equal(200);
expect((r.json.data || []).some(m => m.id === meterId), '3. in list').to.be.true;

// 4. Filter by key — only meters with this exact key appear.
r = await api('GET', `/meters?filter[key]=${encodeURIComponent(meterKey)}`);
expect(r.status, '4. Filter by key → 200').to.equal(200);
const filtered = r.json.data || [];
expect(filtered.some(m => m.id === meterId), '4. created meter in filtered list').to.be.true;
expect(filtered.every(m => m.key === meterKey), '4. only matching key in filtered list').to.be.true;

// 5. Update name, description, and dimensions (aggregation/value_property are immutable).
r = await api('PUT', `/meters/${meterId}`, {
  name: `Updated Meter ${sfx}`,
  description: 'updated description',
  dimensions: { model: '$.model', type: '$.type' }
});
expect(r.status, '5. Update → 200').to.equal(200);
expect(r.json.name, '5. updated name').to.equal(`Updated Meter ${sfx}`);
expect(r.json.description, '5. description').to.equal('updated description');
expect(r.json.dimensions && r.json.dimensions.type, '5. added dimension type').to.equal('$.type');
expect(r.json.aggregation, '5. aggregation unchanged').to.equal('sum');
expect(r.json.value_property, '5. value_property unchanged').to.equal('$.tokens');

// 6. Delete.
r = await api('DELETE', `/meters/${meterId}`);
expect(r.status, '6. Delete → 204').to.equal(204);

// 7. Get after delete — meters are soft-deleted; resource remains retrievable with deleted_at set.
r = await api('GET', `/meters/${meterId}`);
expect(r.status, '7. Get after delete → 200').to.equal(200);
expect(r.json.deleted_at, '7. deleted_at set').to.be.ok;

