// 1. count aggregation without value_property → 201 (valid).
let r = await api('POST', '/meters', {
  key: `count_meter_${sfx}`,
  name: `Count Meter ${sfx}`,
  aggregation: 'count',
  event_type: 'api_call'
});
expect(r.status, '1. count without value_property → 201').to.equal(201);
const countMeterId = r.json.id;
expect(countMeterId, '1. id present').to.be.ok;

// 2. count aggregation with value_property → 400 (forbidden).
r = await api('POST', '/meters', {
  key: `count_meter2_${sfx}`,
  name: `Count Meter 2 ${sfx}`,
  aggregation: 'count',
  event_type: 'api_call',
  value_property: '$.tokens'
});
expect(r.status, '2. count with value_property → 400').to.equal(400);

// 3. sum aggregation without value_property → 400 (required).
r = await api('POST', '/meters', {
  key: `sum_meter_${sfx}`,
  name: `Sum Meter ${sfx}`,
  aggregation: 'sum',
  event_type: 'api_call'
});
expect(r.status, '3. sum without value_property → 400').to.equal(400);

// Cleanup: delete the count meter created in step 1.
await api('DELETE', `/meters/${countMeterId}`);

